var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_QM","text":{"KOREA":"사장님…! 사장님……!","JPN":"社長……！　社長……！","ENG":"Boss...! Boss...!","TWN":"老闆…！老闆……！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_QM","text":{"KOREA":"정신 차려! 젠장, 눈 좀 떠 보라고……!","JPN":"しっかりして！　くそ……目、覚ましてよ……！","ENG":"Snap out of it! C'mon, open your eyes...!","TWN":"你醒醒！該死，睜開眼睛……！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"미나 양……?","JPN":"ミナ君……？","ENG":"Mina...?","TWN":"米娜……？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"사장님? 괜찮아…? 정신이 좀 들어……?","JPN":"社長？　大丈夫……？　気がついた？","ENG":"Boss? You okay...? Can you tell where you are...?","TWN":"老闆？你沒事吧…？意識還清楚嗎…？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"하아, 다행이다. 난 또 사장님이 어떻게 되는 줄 알고…….","JPN":"はあ、よかった。社長に何かあったらと思って……","ENG":"Whew, thank goodness. I thought something had really happened to you...","TWN":"呼，太險。我怕老闆又出什麼事……"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네가 날 감싸준 건가?","JPN":"君がかばってくれたのか？","ENG":"Did you take care of me?","TWN":"是你護住我的嗎？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이거 고맙군. 병원 신세 진지 얼마 지나지도 않는데, 하마터면 또 입원할 뻔했어.","JPN":"すまないな。退院したばかりだというのに、また入院させてしまうところだった。","ENG":"Thanks. I'd barely left the hospital and almost ended up back inside.","TWN":"謝謝你。才剛出院，差點又要進醫院了。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"감사 인사를 하려면, 노엘한테 해.","JPN":"お礼はノエルに言って。","ENG":"If you're thanking anyone, thank Noelle.","TWN":"要道謝的話，就去找洛艾兒吧。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"노엘이 요격해 주지 않았다면, 우리 둘 다 커다란 잔해 속에 파묻혔을 테니까.","JPN":"私たちが巨大な瓦礫に埋もれずにすんだのは、ノエルが迎撃してくれたおかげだから。","ENG":"If she hadn't intercepted it, we'd both be buried in rubble.","TWN":"如果不是洛艾兒出手，我們兩個都會被埋在巨大的殘骸中。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"카운터인 나는 괜찮다고 해도, 사장님은 아니잖아?","JPN":"カウンターの私はともかく、社長はそうなったら危ないでしょ？","ENG":"I'm a Counter, so I'd survive. But you wouldn't have.","TWN":"我是制裁者還好，但老闆你又不是。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그건 그렇군.","JPN":"そうだな。","ENG":"That's true.","TWN":"……那倒是。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그보다 미나 양… 우리 지금 너무 가까운 거 같네만……?","JPN":"それよりミナ君……距離が近すぎないか……？","ENG":"Still, Mina... We're awfully close right now...","TWN":"不過米娜……我們現在是不是靠得太近了……？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이러다가 누가 이 모습을 보기라도 하면…….","JPN":"誰かに見られでもしたら……","ENG":"If someone saw us like this...","TWN":"要是被人看到……"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"음……?","JPN":"うん……？","ENG":"Huh...?","TWN":"嗯……？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아, 아앗! 무슨 생각을 하는 거야, 이런 상황에서!","JPN":"あ、ああっ！　何考えてるんだよ、こんな状況で！","ENG":"W-what are you even thinking about at a time like this?!","TWN":"啊啊！這種情況下你還在想什麼呢！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"어쩔 수 없잖아! 이건 사장님을 구하려다가……","JPN":"だって仕方ないでしょ！　これは社長を助けようとして……","ENG":"I didn't have a choice! I was trying to save you—","TWN":"又不是故意的！這都是為了救老闆……"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"음!?","JPN":"っ！？","ENG":"Mm?!","TWN":"嗯！？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"미나 선배! 사장님! 두 분 다 괜찮으세요……","JPN":"ミナ先輩！　社長！　二人ともご無事で……","ENG":"Mina! Boss! Are you both all ri–","TWN":"米娜前輩！老闆！你們都沒事吧……"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"헉!?","JPN":"はっ！？","ENG":"Eek?!","TWN":"嗯？!"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"충격! 미나 선배의 공격적인 어프로치……!?","JPN":"ショック！　ミナ先輩のアグレッシブなアプローチ……！？","ENG":"Shocking! Mina going in with bold moves...?!","TWN":"震驚！米娜前輩帶有攻擊性的接近……！？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그렇군요…! 짐작은 하고 있었지만, 어쩌면 미나 선배와 사장님은 사실 그렇고 그런……!","JPN":"そうだったんですね……！　そんな気はしていましたが、ミナ先輩と社長は実はそういう関係……！","ENG":"So it's true...! I suspected, but maybe you two really are–!","TWN":"原來如此…！雖然我早就猜想過，但沒想到米娜前輩和老闆其實是那種關係……！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"무슨 헛소리야!","JPN":"バカなこと言うんじゃないよ！","ENG":"Nonsense!","TWN":"說什麼呢！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"저, 저는 괜찮아요! 선배도 사장님도 둘 다 좋으니까!","JPN":"わ、私は平気ですよ！　先輩も社長も好きだから！","ENG":"It's fine! I like both of you, so I'm okay with it!","TWN":"不，不用在乎我！前輩和老闆的話我可以接受！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"네가 생각하는 그런 거 아니거든……!?","JPN":"あなたが思っているような関係じゃないから……！","ENG":"It's not what you think...!","TWN":"不是你想的那樣……！?"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그보다 그렇게 멀뚱멀뚱 보고만 있지 말고 좀 도와달라고!","JPN":"それより、ぼうっと見てないで手伝ってよ！","ENG":"Instead of gawking, give me a hand here!","TWN":"別光站在那裡發呆，快來幫幫我！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"내가 위에서 갑자기 움직이면, 사장님이 잔해에 다칠 수도 있단 말이야!","JPN":"私が急に動いたら、瓦礫で社長が怪我するかもしれない！","ENG":"If I move wrong, Boss could get crushed!","TWN":"如果我在上面突然移動，老闆可能會被碎片傷到！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"엇! 잠시만요, 사장님! 금방 꺼내드릴게요!","JPN":"あっ！　ちょっよ待ってくださいね、社長！　すぐに助けます！","ENG":"Right! Hold on, Boss, I'll get you out!","TWN":"喔！等等，老闆！我馬上來幫你！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이거 두 사람에게 또 신세를 지는군.","JPN":"二人にはまた世話になってしまったな。","ENG":"Once again, I owe you one.","TWN":"又要麻煩你們兩個了。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"으음?","JPN":"ん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L46_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"최고 관리자 들려…? 긴급한 사항이야, 전 세계 대균열에서……","JPN":"最高管理者、聞こえているか……？　緊急事態だ。全世界の大亀裂から……","ENG":"Supreme Administrator, do you hear me...? This is urgent. The Grand Dimension Crevices all over the world are–","TWN":"最高管理者，有聽到嗎……？這是緊急情況，全球大峽谷正在……"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"헙!?","JPN":"はっ！？","ENG":"Huh?!","TWN":"嚇！？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L49_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"르네 양……?","JPN":"ルネ君……？","ENG":"Renée...?","TWN":"芮妮……？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이, 이거 오랜만이군, 그동안 잘 지냈나……?","JPN":"こ、これは久しぶりだな。元気にしていたか……？","ENG":"I-it's been a while. How have you been...?","TWN":"好，好久不見，這段時間過得好嗎……？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"최, 최, 최고 관리자…? 다, 당신 지금 무슨 파렴치한 짓을 저지르고 있는 거야……!?","JPN":"さ、さ、最高管理者……？　あ、あなた、なんて破廉恥なことをしているんだ……！？","ENG":"S-Supreme Administrator...? W-what disgraceful thing are you doing...?!","TWN":"最，最，最高管理者……？你，你現在在做什麼丟人的事……！？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L2_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"전 세계가 혼란에 빠졌는데, 관리자씩이나 되는 사람이 여자랑 뒹굴고 있다고!?","JPN":"全世界が混乱に陥ってるというのに、管理者ともあろう者が女と戯れているとは！？","ENG":"The world's in chaos, and you're playing around with a girl?!","TWN":"全世界都陷入混亂了，身為管理者居然在和女人廝混！？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아니, 그러니까 이건 오해일세…….","JPN":"いや、これは誤解だ……","ENG":"It's not what it looks like...","TWN":"那個，這是誤會……"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"오해는 무슨 오해!","JPN":"言い訳無用！","ENG":"Not what it looks like?!","TWN":"誤會，什麼誤會！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"바른대로 말해! 처음부터 그 애랑 그렇고 그런 사이였어……!?","JPN":"白状しろ！　その子とは最初からそういう関係だったのか……！？","ENG":"Spill it! Were you involved with her from the start...?!","TWN":"你老實說！你們一開始就那種關係嗎……！？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"크, 크흠…! 대충 상황은 이해했어.","JPN":"ご、ごほん……！　大体理解した。","ENG":"A-ahem...! Whatever. I get the situation.","TWN":"咳，咳咳…！我明白事情的來龍去脈了。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"내가 뭐랬나? 처음부터 오해라고 했을텐데?","JPN":"だから最初から言っただろう。誤解だと。","ENG":"What did I say? Misunderstanding from the start.","TWN":"我怎麼說的？我一開始就說是個誤會吧？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"시, 시끄러워! 당신이 맨날 여자랑 붙어 다니니까 그런 거 아니야!","JPN":"う、うるさい！　あなたがいつも女とくっついているからじゃないか！","ENG":"Shut up! It's your fault you're always clinging to women!","TWN":"你，你閉嘴！還不是因為你總是和女人混在一起！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그보다 긴급 사항이라고 하지 않았나?","JPN":"それより、緊急事態だと言っていなかったか？","ENG":"Didn't you say something was urgent?","TWN":"不是說有緊急情況嗎？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"서로 잡담이나 하고 있을 때는 아닌 것 같네만?","JPN":"お互い、雑談でも交わしているほど暇ではないと思うのだが。","ENG":"Now's not the time for chit-chat.","TWN":"現在可不是閒聊的時候吧？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"……나도 알고 있거든?","JPN":"……言われなくてもわかっている！","ENG":"...Of course I know that.","TWN":"……誰不知道？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"현재, 전 세계에서 동시다발적으로 대균열 확장이 관측됐어.","JPN":"現在、全世界で同時多発の大亀裂拡張が観測されている。","ENG":"Right now, simultaneous expansions are being observed in the Grand Dimension Crevices worldwide.","TWN":"目前，觀測到大峽谷在全球範圍內同時擴張。"},"stage":{"bg":"MS_1204_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"이에 따라, 대균열 영역권에 있는 직할 도시, 전 구역에서 CSE 레벨이 상승하고 있고.","JPN":"それに伴い、大亀裂領域圏内にある直轄都市、全区域のCSEレベルが上昇。","ENG":"As a result, CSE levels are rising across all Direct Control Cities within the area.","TWN":"因此，位於大峽谷區域的直轄市，全區域的CSE等級都在上升。"},"stage":{"bg":"MS_1204_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"앞으로 얼마나 확장할지는 모르겠지만, 균열로부터 발생하는 빛이 점점 강해지고 있어.","JPN":"どこまで拡張するかは分からないが、亀裂から発生している光が段々強くなっている。","ENG":"No telling how far it'll spread, but the light from them is growing stronger.","TWN":"今後會擴張到什麼程度我不知道，但從裂縫中產生的光越來越強了。"},"stage":{"bg":"MS_1204_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"어쩌면 조만간 대균열에 의한 백야 현상이 발생할지도 몰라.","JPN":"もしかすると、近いうちに大亀裂による白夜現象が起こるかもしれない。","ENG":"We may soon see a Grand Dimension Crevice-born white night phenomenon.","TWN":"說不定不久後就會因為大峽谷而發生白夜現象。"},"stage":{"bg":"MS_1204_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"당신이라면… 이게 무슨 뜻인지 알고 있겠지……?","JPN":"あなたなら……これが何を意味するか、分かるだろう？","ENG":"You... understand what that means, don't you...?","TWN":"你應該知道這是什麼意思吧……？"},"stage":{"bg":"MS_1204_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MS_1204_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"지금까지 전 세계 대균열에서 동시에 이런 현상이 관측됐던 건 딱 두 번이야.","JPN":"今まで、全世界の大亀裂で同時にこんな現象が観測されたのは2回だけしかない。","ENG":"It's only ever happened twice before, simultaneously across all the Grand Dimension Crevices.","TWN":"到目前為止，全世界的大峽谷中同時觀測到這種現象的情況只發生過兩次。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"당신이 멋대로 클리포트 게임인지, 뭔지를 벌였을 때랑…….","JPN":"あなたが勝手にクリフォトゲームとやらを始めた時と……","ENG":"Once when you started that so-called Qliphoth Game...","TWN":"一次是你擅自開始逆卡巴拉遊戲的時候……"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그리고 우리의 모든 관리가 실패로 돌아갔을 때지.","JPN":"私たちによる管理のすべてが失敗に終わった時だ。","ENG":"And once when all our operations started falling apart.","TWN":"還有一次是我們管理都失敗的時候。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"역시…….","JPN":"やはり……","ENG":"Just as I thought...","TWN":"果然……"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"당신은 이 사태에 관해 뭔가 알고 있는 모양이네.","JPN":"あなたはこの事態について、何か知っているんだな。","ENG":"You clearly know something about this.","TWN":"看來你對這個事態有所瞭解呢。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그래서? 당신이라면 무슨 대책이 있겠지?","JPN":"それで、どうする？　何か対策があるんだろう？","ENG":"So? You must have some plan, don't you?","TWN":"所以呢？你有什麼對策嗎？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"모두 서두르세요.","JPN":"皆さん、急いでください。","ENG":"Everyone, hurry.","TWN":"請大家快點。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"현 시간부로 관리국 최고 등급 재난 경보가 발령되었습니다.","JPN":"現時刻をもって、管理局最高ランクの災難警報が発令されました。","ENG":"As of now, the Administration has issued the highest-level disaster alert.","TWN":"目前管理局已發佈最高級別的災難警報。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"모든 관리국 요원들은 지금 즉시 직할 도시에 있는 시민들의 안전을 확보.","JPN":"全管理局要員は直ちに直轄都市の市民の安全を確保。","ENG":"All personnel, secure citizen safety in Direct Control Cities immediately.","TWN":"所有管理局人員請立即確保直轄市市民的安全。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"재건 도시로의 피난을 유도해주세요.","JPN":"再建都市への避難を誘導してください。","ENG":"Guide evacuations to the Rebuilt Cities.","TWN":"並引導他們到重建城市避難。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"반복합니다… 현 시간부로 관리국은 최고 등급 재난 경보가 발령…….","JPN":"繰り返します……現時刻をもって、管理局最高ランクの災難警報が発令……","ENG":"Repeating... the Administration has issued the highest-level disaster alert...","TWN":"重複……目前管理局已發佈最高級別災難警報……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"……듣고 있지, 최고 관리자?","JPN":"……聞こえているよな？　最高管理者。","ENG":"...You hear that, Supreme Administrator?","TWN":"……你有在聽嗎，最高管理者？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L48_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"우선은 내 권한으로, 이곳 그라운드 원은 관리국 최고 등급 재난 경보를 발령시켰어.","JPN":"まずは私の権限で、ここグラウンド・ワンに管理局最高ランクの災難警報を発令した。","ENG":"I've already declared the alert here in Ground One under my authority.","TWN":"首先，我已經用我的權限在G1發佈管理局最高等級的災難警報。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"당장 연락이 닿는 시니어들은 전부 설득을 마쳤고.","JPN":"すぐに連絡が取れたシニアは全員説得済みだ。","ENG":"The other Seniors I reached out to have agreed.","TWN":"目前已經說服所有能聯絡到的Senior。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그 히키코모리랑 우락부락한 근육남도 곧 자기 도시에 재난 경보를 발령할 거야.","JPN":"あの引きこもりと筋肉男も、もうすぐ自分の都市に災難警報を発令するだろう。","ENG":"Even that shut-in and the muscle-head will declare it in their cities.","TWN":"那個宅男和肌肉男也很快會在自己的城市發佈災難警報。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE"},{"id":"L3_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"하지만 아직 안심하기는 일러.","JPN":"だが、安心するにはまだ早い。","ENG":"But it's too soon to breathe easy.","TWN":"但現在還不能放心。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"샤레이드는 임시 권한 대행인 내가 어떻게든 사태를 수습하고 있지만.","JPN":"シャレードは臨時権限代行である私がなんとか事態を収拾しているが。","ENG":"Charade's under control for now since I'm acting authority.","TWN":"雖然查雷德有我這個臨時代理人努力處理中，"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"당신도 알다시피, 현재 챔버 쪽은 시니어 잭슨의 행방이 묘연한 상태거든.","JPN":"あなたも知っている通り、チェンバーのほうはシニア・ジャクソンが行方不明だからな。","ENG":"But as you know, Chamber's Senior Jackson is missing.","TWN":"我們目前對強巴那邊的Senior傑森的下落一無所知。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"게다가 캄파멘토 관리국 측에서도 요인 구출 요청이 들어왔어.","JPN":"それに、カンパメント管理局側からも要人救出の要請が来ている。","ENG":"And Campamento requested extraction for their key figure.","TWN":"而且坎帕門托管理局那邊也發來救援請求。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"분명, 허풍쟁이 칸 영감이 또 무슨 사고를 친 거겠지. 나 참 이런 상황에…….","JPN":"きっとあのホラ吹きのカン爺さんが、また何かやらかしたのだろう。","ENG":"That boastful codger Khan must've caused trouble again, even now...","TWN":"肯定是坎那個老傢伙又惹了什麼麻煩。唉，這種情況下……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE"},{"id":"L12_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"최고 관리자… 당신, 지금 듣고 있는 거 맞지……?","JPN":"最高管理者……私の話、聞いているか？","ENG":"Supreme Administrator... you are listening, aren't you...?","TWN":"最高管理者……你有在聽我說話吧……？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"뭐라고 말 좀 해봐. 당신한테 뭔가 대책이 있는 거지……?","JPN":"返事をしろ。あなたは何か対策があるんだろう……？","ENG":"Say something. You must have a plan...?","TWN":"你說點什麼吧。你一定有什麼對策吧……？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"……사실은.","JPN":"……実は。","ENG":"...The truth is.","TWN":"……其實。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그래, 사실은 나도 알고 있어.","JPN":"ああ、実は私も分かっている。","ENG":"Yes. I know.","TWN":"其實我也知道。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"멋대로 권한을 동결시키고, 이제와서 대책을 요구하는 게 뻔뻔하다는 것쯤은…….","JPN":"勝手に権限を凍結しておいて、今更対策を要求するなんて図々しいにもほどがあるよな……","ENG":"I know it's shameless to suspend your authority and then demand answers now...","TWN":"我知道我擅自凍結權限，現在又要求你來想對策，真的很厚臉皮……"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"하지만 지난 몇 개월 간, 당신은 내가 감당할 수 없는 문제를 해결해 왔잖아?","JPN":"だがこの数か月間、あなたは私の手に負えない問題を解決してきた。","ENG":"But these past months, you've solved problems I couldn't.","TWN":"但是在過去的幾個月裡，你不是一直在解決我無法處理的問題嗎？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"샤레이드 시니어의 죽음으로 인해, 혼란해진 도시의 질서를 지켜냈고…….","JPN":"シャレードのシニアの死で混乱している都市の秩序を守り……","ENG":"When Charade's Senior died, you upheld order in a city spiraling...","TWN":"在查雷德Senior死後，維護混亂的城市秩序……"},"stage":{"bg":"CHARADE2_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"지금껏 유래가 없었던 관리국 최고 등급 재난 경보…….","JPN":"前例のなかった、管理局最高ランクの災難警報……","ENG":"You faced an unprecedented highest-level disaster alert...","TWN":"管理局最高等級災難警報響起後……"},"stage":{"bg":"MS_1203","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"클리포트 마왕의 현실 강림을 저지했어.","JPN":"クリフォトの魔王の現実降臨を阻止した。","ENG":"And stopped the Demon Lord's descent into reality.","TWN":"阻止逆卡巴拉魔王降臨現世。"},"stage":{"bg":"MS_1203","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"관리 경계 구역 상공에 출몰했던 거대한 미확인 비행물체……","JPN":"管理警戒区域上空に現れた、巨大な未確認飛行物体……","ENG":"That massive unidentified flying object over the perimeter zone...","TWN":"管理警戒區域上空出現的巨大不明飛行物……"},"stage":{"bg":"MS_1407","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"나로서는 무슨 일이 있었는지 짐작도 안 되지만, 그 사태를 해결한 것도 당신이겠지?","JPN":"私には何があったのか見当もつかないが、あの事態を解決したのもあなただろう？","ENG":"I can't even guess what really happened, but you solved it, didn't you?","TWN":"我完全猜不到發生什麼事，但解決那件事的也是你吧？"},"stage":{"bg":"MS_1407","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MS_1407","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"지난 사태들을 해결하면서, 당신은 실력을 충분히 증명했다고 생각해.","JPN":"これらの事件を解決したことで、あなたは自分の実力を十分証明してみせた。","ENG":"Through all of that, you proved yourself.","TWN":"透過解決最近的事件，我認為你已經充分證明自己的實力。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그리고 우리 세계는 또 한 번 절체 절명의 위기에 다다랐지.","JPN":"そして我々の世界は再び絶体絶命の危機に直面している。","ENG":"And now our world faces another crisis.","TWN":"而我們的世界再次面臨生死存亡的危機。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"분하지만, 인정할게. 지금 이 사태는 나 혼자서는…….","JPN":"悔しいが、認めざるを得ない。この事態は私一人の力では……","ENG":"As much as I hate to admit it, I can't handle this alone...","TWN":"雖然不甘心，但我承認。現在這種情況，我一個人是……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"아니, 여섯 도시 시니어의 힘으로는 이 사태를 <color=#ffd34c>관리</color>하는 게 불가능 해.","JPN":"いや、6つの都市のシニアの力では、この事態は<color=#ffd34c>管理</color>できない。","ENG":"No, the six Seniors together can't <color=#ffd34c>manage</color> this crisis.","TWN":"不，靠我們六個城市Senior的力量，是無法<color=#ffd34c>解決</color>這種情況的。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L40_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"내가 오만했어, 최고 관리자.","JPN":"私が傲慢だった、最高管理者。","ENG":"I was arrogant, Supreme Administrator.","TWN":"是我太驕傲了，最高管理者。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그라운드 원의 2급 관리자로서, 사죄라면 얼마든지 할게.","JPN":"グラウンド・ワンの2級管理者として、いくらでも謝罪しよう。","ENG":"As Ground One's Class 2 Administrator, I'll apologize as much as you'd like.","TWN":"作為G1的2級管理者，我隨時可以向你賠罪。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그러니까……","JPN":"だから……","ENG":"So please...","TWN":"所以……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그러니까 가르쳐 줘, 최고 관리자… 우리가 어떻게 하면 돼……?","JPN":"だから教えてくれ、最高管理者……私たちは何をすればいい……？","ENG":"Tell me, Supreme Administrator... What should we do...?","TWN":"最高管理者，請告訴我…我們該怎麼辦…？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"어떻게 하면… 이 사태를 막을 수 있지……?","JPN":"どうすれば……この事態を止めることができる……？","ENG":"How do we stop... this disaster...?","TWN":"要怎麼做……才能阻止這場災難……？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"관리자인 당신이라면, 할 수 있잖아?","JPN":"管理者のあなたになら、できるだろう？","ENG":"If anyone can, it's you... right?","TWN":"如果是管理者你的話，應該做得到吧？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"……틀렸네, 르네 양.","JPN":"……違うぞ、ルネ君。","ENG":"...You're wrong, Renée.","TWN":"……不，芮妮。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"나 역시 자네들처럼 그저 평범한 인간에 불과해.","JPN":"私は君たちと同じく、普通の人間だ。","ENG":"I'm only human, like you.","TWN":"我跟你們一樣都是普通人。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"나라고 모든 걸 관리할 수는 없어.","JPN":"私とてすべてを管理することはできない。","ENG":"I can't manage everything.","TWN":"我也無法管理所有事情。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그, 그럼……?","JPN":"で、では……？","ENG":"Th-then...?","TWN":"那，那……？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 인간은 항상 실패로부터 배우고, 조금씩 앞으로 나아가지.","JPN":"しかし人間は常に失敗から学び、少しずつ前に進む。","ENG":"But humans learn from failure. They move forward, step by step.","TWN":"但人類總是能在失敗當中學習，並一點一點地進步。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네가 지난 사태로부터 배우고, 즉시 관리국 최고 등급 재난 경보를 발령한 것처럼.","JPN":"君が過去の事件から学び、迅速に管理局最高ランクの災難警報を発令したようにね。","ENG":"Just as you learned from the last disaster and declared the alert without delay.","TWN":"就像你從上次事件中吸取教訓，立即發佈管理局最高級別災難警報一樣。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"훌륭한 대처였네, 르네 양. 덕분에 민간 피해를 줄일 수 있을지도 모르겠군.","JPN":"立派な対処だった、ルネ君。君のおかげで民間人の被害が抑えられるかもしれないな。","ENG":"That was well done, Renée. It may save countless civilians.","TWN":"你做得很好，芮妮。幸虧有你，或許能減少民眾的損失。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"차, 착각하지 마…! 나는 당신한테 칭찬받고 싶던 게 아니야……!","JPN":"か、勘違いするな……！　私はあなたに褒められたかったわけではない……！","ENG":"D-don't get the wrong idea...! I didn't do it for your praise...!","TWN":"別，別誤會……！我才不是想要得到你的稱讚……！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"나는 그저… 시니어로서 내 역할을……!","JPN":"私はただ……シニアとして自分の役目を……！","ENG":"I just... did my duty as a Senior...!","TWN":"我只是……盡Senior該盡的職責……！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"역할이라… 그래, 그렇군…….","JPN":"役目か……ああ、そうだな……","ENG":"Duty... Yes, I see...","TWN":"職責嗎……原來如此……"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇기에 나는 결국 자네들을… 그리고 이 세계를 포기할 수 없는 거겠지…….","JPN":"だからこそ私は君たちを……そしてこの世界を諦められないのだろう……","ENG":"That's why I can't give up on you... or this world...","TWN":"所以我無法放棄你們……和這個世界……"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"내게 더는 물러날 곳이 없다고 하더라도…….","JPN":"私にもう後がないとしても……","ENG":"Even if I have nowhere left to retreat...","TWN":"即使我已經無路可退……"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"내 앞을 가로 막는 것이 한치 앞조차 내다볼 수 있는 절망이라고 하더라도…….","JPN":"真っ暗な絶望が私の前に立ちはだかろうとも……","ENG":"Even if despair itself bars the path ahead...","TWN":"即使擋在我面前的是無法預見的絕望……"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"나는 손에 쥔 작은 <color=#ffd34c>희망</color>을 절대 포기하지 못할 거야.","JPN":"私はこの手にある小さな<color=#ffd34c>希望</color>を決して諦められない。","ENG":"I'll never let go of the small <color=#ffd34c>hope</color> in my hands.","TWN":"我絕不會放棄手中握著的那一絲<color=#ffd34c>希望</color>。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그게 내 <color=#ffd34c>역할</color>이니까.","JPN":"それが私の<color=#ffd34c>役目</color>だからな。","ENG":"Because that's my <color=#ffd34c>duty</color>.","TWN":"因為這是我的<color=#ffd34c>職責</color>。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"최고 관리자, 당신……?","JPN":"最高管理者、あなた……？","ENG":"Supreme Administrator, are you–?","TWN":"最高管理者，你……？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"르네 양.","JPN":"ルネ君。","ENG":"Renée.","TWN":"芮妮。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"전조 프로토콜이 발동한 직후…….","JPN":"前兆プロトコル発動直後……","ENG":"When the Omen protocol triggered...","TWN":"前兆協定啟動後……"},"stage":{"bg":"MAINSTREAM_000005","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"나는 내 인력을 최대한 동원하여, 각 도시에 적절한 인원을 선별하고 파견해 두었네.","JPN":"私はできる限りの人員を動員し、各都市に適切な人物を派遣しておいた。","ENG":"I mobilized my people, dispatching support to each city.","TWN":"我已經盡可能動員我的人力，挑選並派遣適當的人選到各個城市。"},"stage":{"bg":"MAINSTREAM_000005","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 이건 어디까지나 최소한의 대비책일 뿐이야.","JPN":"しかしこれは最低限の対策にすぎない。","ENG":"But those were only minimal precautions.","TWN":"但這只是最低限度的應對措施而已。"},"stage":{"bg":"MAINSTREAM_000005","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"앞으로는 무슨 일이 일어날 지는 나조차도 확신할 수 없어.","JPN":"これから何が起こるかについては、私も確信できない。","ENG":"Even I can't say what comes next.","TWN":"今後會發生什麼事，我自己也無法確定。"},"stage":{"bg":"MAINSTREAM_000005","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"다시 말해…….","JPN":"つまり……","ENG":"In other words...","TWN":"就是說……"},"stage":{"bg":"MAINSTREAM_000005","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네들이 내 도움이 필요한 것처럼, 나 또한 자네들의 도움이 필요하다네.","JPN":"君たちが私の助けを求めているように、私もまた、君たちの助けを求めている。","ENG":"Just as you need me, I need you.","TWN":"就像你們需要我的協助一樣，我也需要你們的協助。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L31_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이번에야말로 각 도시 관리국의 협력이 없다면, 이 세계를 지켜낼 수 없을 테니까.","JPN":"今度こそ、各々の都市管理局が互いと協力し合わない限り、この世界は守りきれないだろうから。","ENG":"Without cooperation from every Administration, we won't save this world.","TWN":"這次如果各城市管理局不能通力合作的話，我們將無法守護這個世界。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"……알겠어.","JPN":"……分かった。","ENG":"...Understood.","TWN":"……明白。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"당장 다른 관리국에도 그렇게 전할게! 그밖에도 필요한 게 있으면, 얼마든지 말만 해!","JPN":"今すぐ他の管理局に伝えておく。他にも必要なことがあれば何でも言ってくれ！","ENG":"I'll alert the others immediately. If you need anything else, just say it!","TWN":"我會立刻通知其他管理局！如果還有其他需要，儘管告訴我！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"상황이 상황인 만큼, 시니어로서 내가 전력으로 서포트할 테니까!","JPN":"こんな状況だ、シニアとして私が全力でサポートしよう！","ENG":"As a Senior, I'll give you my full support!","TWN":"在目前這種特殊情況，作為Senior，我會全力支持你的！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그라운드 원에는 미나 양과 노엘 양을 보내겠네.","JPN":"グラウンド・ワンにはミナ君とノエル君を送ろう。","ENG":"I'll send Mina and Noelle to Ground One.","TWN":"我會派米娜和洛艾兒去G1。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L37_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그리고…….","JPN":"そして……","ENG":"And lastly...","TWN":"還有……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"마지막으로 자네가 필요해, 르네 말루프.","JPN":"最後に、君が必要だ。ルネ・マルーフ。","ENG":"I need you, Renée Maalouf.","TWN":"我需要你，芮妮·瑪盧夫。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"알겠어……","JPN":"分かった……","ENG":"Okay...","TWN":"知道了……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"뭐!?","JPN":"何！？","ENG":"Wait, what?!","TWN":"什麼！？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L42_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"나…!? 지금 내가 필요하다고……!?","JPN":"私……！？　今私が必要だと言ったか！？","ENG":"Me...?! You need me...?!","TWN":"我……！？你說需要我……？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"르네 양. 지금 이쪽으로 와 줄 수 있나?","JPN":"ルネ君。今こちらに来てくれないか？","ENG":"Renée. Can you come here, to Lotus?","TWN":"芮妮，你現在能過來嗎？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"자, 자, 자, 잠깐!? 지금 로터스로 가 달라고……?","JPN":"ま、ま、ま、待て！　今ロータスに来いと……？","ENG":"H-hold on! You want me in Lotus, now...?","TWN":"等，等，等，等等！？你要我現在要去洛德斯……？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇네. 촌각을 다투는 문제야.","JPN":"ああ。一刻を争う状況だ。","ENG":"Yes. Every moment counts.","TWN":"沒錯，現在是分秒必爭的時刻。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그, 그렇지만……!","JPN":"だ、だが……！","ENG":"B-but...!","TWN":"是，是沒錯……！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"이건 너무 갑작스럽잖아? 난 아직 마음의 준비가……!?","JPN":"いくら何でも突然すぎるだろう！　私はまだ心の準備が……！","ENG":"It's too sudden! I'm not ready for this...!","TWN":"但這也太突然了吧？我還沒做好心理準備……！？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"정확히 말하자면…….","JPN":"正確に言うと……","ENG":"To be precise...","TWN":"準確地說……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"퓨처 앳 워, 선임 연구원 시절의 자네가 필요해.","JPN":"フューチャーアットウォー、専任研究員時代の君が必要だ。","ENG":"I need you as the senior researcher you were in Future-at-War.","TWN":"是天啟兵器，我需要你在擔任高級研究員時期的經驗。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"퓨처 앳 워라고……?","JPN":"フューチャーアットウォーだと……？","ENG":"Future-at-War...?","TWN":"天啟兵器……？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};